import React from "react";
import moment from "moment";
import "./index.scss";
import ContentBlockArr from "../../components-lib/gante/components/contentBlockArr";
import DateBlockArr from "../../components-lib/gante/components/dateBlockArr";
import RenderBlock from "../../components-lib/gante/components/renderBlock";

export default function() {
  return (
    <div className="page7">
      {renderRenderBlock()}
      {renderDateBlockArr()}
    </div>
  );
}

function renderRenderBlock() {
  const props = {
    posX: 10,
    posY: 40,
    width: 100,
    height: 100,
    content: "RenderBlock",
    background: "red"
  };
  return (
    <div className="show-render-block">
      <h2>RenderBlock</h2>
      <RenderBlock {...props} />
    </div>
  );
}

function renderDateBlockArr() {
  const props = {
    type: "vertical",
    startCalcTime: moment()
      .endOf("day")
      .startOf("h"),
    unitStretch: 10,
    minInterval: "m",
    timeRenderInterval: 10
  };
  return (
    <div className="show-render-block">
      <h2>DateBlockArr</h2>
      <DateBlockArr {...props} />
    </div>
  );
}
