import React from "react";
import { Link } from "react-router-dom";

export default function(props) {
  const id = Number(props.match.params.id);
  return (
    <div>
      <div>
        <Link to={`/page/${id - 1}`}>上一页</Link>
        {id}
        <Link to={`/page/${id + 1}`}>下一页</Link>
      </div>
      {props.children}
    </div>
  );
}
